// For each contact, generate email permutations and prepare verification
const contacts = $input.all();
const results = [];

for (const item of contacts) {
  const c = item.json;
  const nameParts = (c.full_name || '').trim().split(/\s+/);
  if (nameParts.length < 2) continue;

  const first = nameParts[0].toLowerCase();
  const last = nameParts[nameParts.length - 1].toLowerCase();
  const firstInitial = first[0];
  const lastInitial = last[0];

  // Extract domain from website or company name
  let domain = '';
  if (c.website) {
    try {
      domain = new URL(c.website.startsWith('http') ? c.website : `https://${c.website}`).hostname.replace('www.', '');
    } catch(e) {}
  }

  if (!domain && c.company_name) {
    // Guess domain from company name
    domain = c.company_name.toLowerCase()
      .replace(/[^a-z0-9\s]/g, '')
      .replace(/\s+/g, '')
      .substring(0, 30) + '.com';
  }

  if (!domain) continue;

  // Common email patterns (ordered by likelihood)
  const patterns = [
    `${first}.${last}@${domain}`,
    `${first}@${domain}`,
    `${firstInitial}${last}@${domain}`,
    `${first}${last}@${domain}`,
    `${first}_${last}@${domain}`,
    `${first}${lastInitial}@${domain}`,
    `${last}.${first}@${domain}`,
    `${last}@${domain}`
  ];

  results.push({
    ...c,
    domain,
    email_patterns: patterns,
    first_name: nameParts[0],
    last_name: nameParts[nameParts.length - 1],
    pipeline_stage: 'email_lookup'
  });
}

return results.map(r => ({ json: r }));

// Merge results from Hunter and Snov, pick best email
const hunterResults = $('Hunter.io Email Finder').all();
const snovResults = $('Snov.io Email Finder').all();
const originalContacts = $('Generate Email Patterns').all();

const results = [];

for (let i = 0; i < originalContacts.length; i++) {
  const contact = originalContacts[i].json;
  const emails = new Map(); // email -> confidence

  // Parse Hunter result
  const hunterData = hunterResults[i]?.json?.data;
  if (hunterData?.email) {
    emails.set(hunterData.email, {
      email: hunterData.email,
      confidence: hunterData.score || 50,
      source: 'hunter',
      type: hunterData.type || 'unknown'
    });
  }

  // Parse Snov result  
  const snovData = snovResults[i]?.json;
  const snovEmails = snovData?.emails || snovData?.data?.emails || [];
  for (const se of snovEmails) {
    const email = se.email || se;
    if (typeof email === 'string' && email.includes('@')) {
      const existing = emails.get(email);
      if (existing) {
        existing.confidence = Math.min(100, existing.confidence + 20); // Boost if found by both
        existing.source = 'hunter+snov';
      } else {
        emails.set(email, {
          email,
          confidence: se.confidence || se.score || 40,
          source: 'snov',
          type: se.type || 'unknown'
        });
      }
    }
  }

  // If no emails found from APIs, use best guess from patterns
  if (emails.size === 0) {
    const patterns = contact.email_patterns || [];
    if (patterns.length > 0) {
      emails.set(patterns[0], {
        email: patterns[0],
        confidence: 30,
        source: 'pattern_guess',
        type: 'guess'
      });
    }
  }

  // Pick the highest confidence email
  const sorted = Array.from(emails.values()).sort((a, b) => b.confidence - a.confidence);
  const bestEmail = sorted[0];

  results.push({
    ...contact,
    email: bestEmail?.email || '',
    email_confidence: bestEmail?.confidence || 0,
    email_source: bestEmail?.source || 'none',
    email_type: bestEmail?.type || 'unknown',
    all_emails_found: sorted.map(e => e.email),
    pipeline_stage: bestEmail ? 'email_found' : 'email_not_found'
  });
}

return results.map(r => ({ json: r }));

// Process verification results
const verifyResults = $input.all();
const contacts = $('Has Email?').all();

const results = [];

for (let i = 0; i < contacts.length; i++) {
  const contact = contacts[i].json;
  const verification = verifyResults[i]?.json?.data || {};

  const status = verification.status || 'unknown';
  const score = verification.score || 0;

  // Only keep valid/accept_all emails
  const isValid = ['valid', 'accept_all'].includes(status);

  results.push({
    ...contact,
    email_verified: isValid,
    email_status: status,
    email_verification_score: score,
    pipeline_stage: isValid ? 'email_verified' : 'email_invalid',
    ready_for_research: isValid
  });
}

// Filter to only verified emails
return results
  .filter(r => r.email_verified)
  .map(r => ({ json: r }));
